import { useEffect, useMemo, useState } from "react";

const reactIcon = (
  <svg
    className="react-svg"
    viewBox="0 0 841 595"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    aria-hidden="true"
  >
    <circle cx="420.5" cy="296.5" r="40" fill="currentColor" />
    <ellipse
      cx="420.5"
      cy="296.5"
      rx="190"
      ry="75"
      stroke="currentColor"
      strokeWidth="28"
    />
    <ellipse
      cx="420.5"
      cy="296.5"
      rx="190"
      ry="75"
      transform="rotate(60 420.5 296.5)"
      stroke="currentColor"
      strokeWidth="28"
    />
    <ellipse
      cx="420.5"
      cy="296.5"
      rx="190"
      ry="75"
      transform="rotate(120 420.5 296.5)"
      stroke="currentColor"
      strokeWidth="28"
    />
  </svg>
);

const codexIcon = (
  <svg
    className="skill-svg"
    viewBox="0 0 24 24"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    aria-hidden="true"
  >
    <path
      d="M4.5 7.5L12 3l7.5 4.5v9L12 21l-7.5-4.5v-9z"
      stroke="currentColor"
      strokeWidth="1.6"
    />
    <path
      d="M8 10.5h8M8 13.5h5"
      stroke="currentColor"
      strokeWidth="1.6"
      strokeLinecap="round"
    />
  </svg>
);

const vscodeIcon = (
  <svg
    className="skill-svg"
    viewBox="0 0 128 128"
    xmlns="http://www.w3.org/2000/svg"
    aria-hidden="true"
  >
    <path
      d="M92.6 14.7l22.5 10.8v77L92.6 113l-42-38.1 25.3-19.6-25.3-19.5 42-21.1z"
      fill="currentColor"
    />
    <path
      d="M12 49.5l20.6-15.7 21.1 19.9-21.1 19.9L12 58.9c-1.3-1-1.3-3.2 0-4.4z"
      fill="currentColor"
      opacity="0.85"
    />
  </svg>
);

const canvaIcon = (
  <svg
    className="skill-svg"
    viewBox="0 0 24 24"
    xmlns="http://www.w3.org/2000/svg"
    aria-hidden="true"
  >
    <circle cx="12" cy="12" r="9" fill="currentColor" opacity="0.15" />
    <path
      d="M15.8 9.2c-.6-.9-1.6-1.3-2.9-1.3-2.4 0-4.2 1.7-4.2 4.1 0 2.4 1.7 4.1 4.1 4.1 1.2 0 2.2-.4 3-1.3l-.9-.9c-.5.6-1.2.9-2.1.9-1.6 0-2.7-1.1-2.7-2.8 0-1.7 1.1-2.8 2.7-2.8.8 0 1.5.3 2 .9l1-0.9z"
      fill="currentColor"
    />
  </svg>
);

const skillsData = [
  {
    category: "Frontend",
    items: [
      { name: "HTML", icon: "bi-filetype-html", color: "#ff7a18", level: 95 },
      { name: "CSS", icon: "bi-filetype-css", color: "#4dabf7", level: 90 },
      { name: "JavaScript", icon: "bi-filetype-js", color: "#ffd43b", level: 80,},
      { name: "React", icon: bi-react, color: "#5edfff", level: 75 },
      { name: "Bootstrap", icon: "bi-bootstrap", color: "#a370f7", level: 85 },
    ],
  },
  {
    category: "AI Tools & Tech",
    items: [
      { name: "Prompt Engineering", icon: "bi-lightning-charge", color: "#ffb26b", level: 75,},
      { name: "Codex", icon: codexIcon, color: "#ff7a18", level: 78 },
      { name: "VS Code", icon: vscodeIcon, color: "#3ea6ff", level: 92 },
    ],
  },
  {
    category: "Other Skills",
    items: [
      { name: "Git & GitHub", icon: "bi-github", color: "#ffffff", level: 75 },
      { name: "Responsive Design", icon: "bi-phone", color: "#5eead4", level: 85 },
      { name: "UI/UX Design", icon: "bi-vector-pen", color: "#ff9a3c", level: 70 },
      { name: "Canva", icon: canvaIcon, color: "#35c5f0", level: 82 },
    ],
  },
];

const tabs = ["All", "Frontend", "AI Tools & Tech", "Other Skills"];

export default function Skills() {
  const [activeTab, setActiveTab] = useState("All");

  const filtered = useMemo(() => {
    if (activeTab === "All") return skillsData;
    return skillsData.filter((group) => group.category === activeTab);
  }, [activeTab]);

  useEffect(() => {
    const cards = document.querySelectorAll(".skill-card");
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add("in-view");
            observer.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.2 },
    );

    cards.forEach((card) => observer.observe(card));
    return () => observer.disconnect();
  }, [activeTab]);

  return (
    <section id="skills" className="skills-section section">
      <div className="container text-center">
        <span className="section-kicker">Technologies I Work With</span>
        <h2 className="section-title gradient-title">My Skills</h2>
        <p className="section-text mx-auto">
          A focused toolkit for building fast, responsive, and modern web
          experiences with clean UI and smart automation.
        </p>

        <div className="skills-tabs">
          {tabs.map((tab) => (
            <button
              key={tab}
              type="button"
              className={`skills-tab ${activeTab === tab ? "active" : ""}`}
              onClick={() => setActiveTab(tab)}
            >
              {tab}
            </button>
          ))}
        </div>
      </div>

      <div className="container">
        {filtered.map((group) => (
          <div key={group.category} className="skills-group">
            <h3 className="skills-group-title">{group.category}</h3>
            <div className="row g-4">
              {group.items.map((skill) => (
                <div key={skill.name} className="col-12 col-md-6 col-lg-4">
                  <div
                    className="skill-card"
                    title={skill.name}
                    style={{ "--accent-color": skill.color }}
                  >
                    <div className="skill-header">
                      <span className="skill-icon">
                        {typeof skill.icon === "string" ? (
                          <i className={`bi ${skill.icon}`} />
                        ) : (
                          skill.icon
                        )}
                      </span>
                      <div>
                        <h4>{skill.name}</h4>
                        <span className="skill-level">{skill.level}%</span>
                      </div>
                    </div>
                    <div className="skill-progress">
                      <span
                        className="skill-progress-bar"
                        style={{ "--progress": `${skill.level}%` }}
                      />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}
